import heapq

class Solution:
    def mergeKLists(self, lists):
        heap = []
        for index, node in enumerate(lists):
            if node:
                heapq.heappush(heap, (node.val, index, node))
        dummy = ListNode(0)
        tail = dummy
        counter = len(lists)
        while heap:
            _, _, node = heapq.heappop(heap)
            tail.next = node
            tail = tail.next
            if node.next:
                counter += 1
                heapq.heappush(heap, (node.next.val, counter, node.next))
        return dummy.next
